namespace UniversityCourseCatalog.Models;

public class Department
{
    public required string Id { get; init; }
    public required string Name { get; init; }
    public required string Description { get; init; }
}

public class Instructor
{
    public required string Name { get; init; }
    public required string Title { get; init; }
    public required string Bio { get; init; }
    public required string Email { get; init; }
}

public class Course
{
    public required string Id { get; init; }
    public required string DepartmentId { get; init; }
    public required string Code { get; init; }
    public required string Title { get; init; }
    public required string Description { get; init; }
    public required int Credits { get; init; }
    public required string Schedule { get; init; }
    public required string Location { get; init; }
    public required Instructor Instructor { get; init; }
    public required string Level { get; init; } // Undergraduate, Graduate
    public bool IsFeatured { get; init; }
    public int MaxEnrollment { get; init; }
    public int CurrentEnrollment { get; init; }
}

using System.ComponentModel.DataAnnotations;

namespace UniversityCourseCatalog.Models;

public class EnrollmentRequest
{
    [Required(ErrorMessage = "Full name is required.")]
    [StringLength(100, ErrorMessage = "Name cannot exceed 100 characters.")]
    public string FullName { get; set; } = string.Empty;

    [Required(ErrorMessage = "Student ID is required.")]
    [RegularExpression(@"^[A-Z]{1,3}\d{5,8}$", ErrorMessage = "Student ID must be 1–3 uppercase letters followed by 5–8 digits (e.g., CS12345).")]
    public string StudentId { get; set; } = string.Empty;

    [Required(ErrorMessage = "Please select a course.")]
    public string CourseId { get; set; } = string.Empty;

    [EmailAddress(ErrorMessage = "Please enter a valid email address.")]
    [Required(ErrorMessage = "Email address is required.")]
    public string Email { get; set; } = string.Empty;

    public string? Notes { get; set; }
}

