namespace UniversityCourseCatalog.Services;

public class EnrollmentService
{
    private readonly List<EnrollmentRequest> _submissions = [];
    private readonly Lock _lock = new();

    public void Submit(EnrollmentRequest request)
    {
        lock (_lock)
        {
            _submissions.Add(request);
        }
    }

    public IReadOnlyList<EnrollmentRequest> GetAll()
    {
        lock (_lock)
        {
            return _submissions.ToList();
        }
    }
}

using UniversityCourseCatalog.Models;

