@page "/enroll"
@inject CatalogService Catalog
@inject EnrollmentService Enrollments
@inject NavigationManager Nav

<PageTitle>Enrollment Request</PageTitle>

<h1>Enrollment Request</h1>
<p>Complete the form below to submit an enrollment request. All fields marked with <span class="text-danger">*</span> are required.</p>

@if (submitted)
{
    <div class="alert alert-success">
        <h4 class="alert-heading">Request Submitted!</h4>
        <p>
            Thank you, <strong>@Model.FullName</strong>. Your enrollment request for
            <strong>@(Catalog.GetCourse(Model.CourseId)?.Title)</strong> has been received.
        </p>
        <p class="mb-0">You will receive a confirmation at <strong>@Model.Email</strong>.</p>
    </div>
    <a href="courses" class="btn btn-primary">Browse More Courses</a>
}
else
{
    <EditForm Model="Model" FormName="EnrollmentForm" OnValidSubmit="HandleSubmit" method="post">
        <DataAnnotationsValidator />
        <ValidationSummary class="text-danger mb-3" />

        <div class="row">
            <div class="col-md-6 mb-3">
                <label for="fullName" class="form-label">Full Name <span class="text-danger">*</span></label>
                <InputText id="fullName" @bind-Value="Model.FullName" class="form-control" />
                <ValidationMessage For="() => Model.FullName" class="text-danger" />
            </div>

            <div class="col-md-6 mb-3">
                <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" placeholder="e.g., CS12345" />
                <ValidationMessage For="() => Model.StudentId" class="text-danger" />
            </div>
        </div>

        <div class="row">
            <div class="col-md-6 mb-3">
                <label for="email" class="form-label">Email Address <span class="text-danger">*</span></label>
                <InputText id="email" @bind-Value="Model.Email" class="form-control" />
                <ValidationMessage For="() => Model.Email" class="text-danger" />
            </div>

            <div class="col-md-6 mb-3">
                <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select">
                    <option value="">— Select a course —</option>
                    @foreach (var dept in Catalog.GetDepartments())
                    {
                        <optgroup label="@dept.Name">
                            @foreach (var c in Catalog.GetCoursesByDepartment(dept.Id))
                            {
                                <option value="@c.Id">@c.Code — @c.Title (@c.Credits cr.)</option>
                            }
                        </optgroup>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.CourseId" class="text-danger" />
            </div>
        </div>

        <div class="mb-3">
            <label for="notes" class="form-label">Additional Notes</label>
            <InputTextArea id="notes" @bind-Value="Model.Notes" class="form-control" rows="3"
                           placeholder="Any special requests or accommodations…" />
            <ValidationMessage For="() => Model.Notes" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
        <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
}

@code {
    [SupplyParameterFromForm]
    private EnrollmentRequest Model { get; set; } = new();

    [SupplyParameterFromQuery(Name = "course")]
    public string? PreselectedCourse { get; set; }

    private bool submitted;

    protected override void OnInitialized()
    {
        if (!string.IsNullOrEmpty(PreselectedCourse) && string.IsNullOrEmpty(Model.CourseId))
        {
            Model.CourseId = PreselectedCourse;
        }
    }

    private void HandleSubmit()
    {
        Enrollments.Submit(Model);
        submitted = true;
    }
}

