            </div>

            <div class="col-md-6 mb-3">
                <label for="studentId" class="form-label">Student ID <span class="text-danger">*</span></label>
                <InputText id="studentId" @bind-Value="Model.StudentId" class="form-control" placeholder="e.g., CS12345" />
                <ValidationMessage For="() => Model.StudentId" class="text-danger" />
            </div>
        </div>

        <div class="row">
            <div class="col-md-6 mb-3">
                <label for="email" class="form-label">Email Address <span class="text-danger">*</span></label>
                <InputText id="email" @bind-Value="Model.Email" class="form-control" />
                <ValidationMessage For="() => Model.Email" class="text-danger" />
            </div>

            <div class="col-md-6 mb-3">
                <label for="courseId" class="form-label">Course <span class="text-danger">*</span></label>
                <InputSelect id="courseId" @bind-Value="Model.CourseId" class="form-select">
                    <option value="">— Select a course —</option>
                    @foreach (var dept in Catalog.GetDepartments())
                    {
                        <optgroup label="@dept.Name">
                            @foreach (var c in Catalog.GetCoursesByDepartment(dept.Id))
                            {
                                <option value="@c.Id">@c.Code — @c.Title (@c.Credits cr.)</option>
                            }
                        </optgroup>
                    }
                </InputSelect>
                <ValidationMessage For="() => Model.CourseId" class="text-danger" />
            </div>
        </div>

        <div class="mb-3">
            <label for="notes" class="form-label">Additional Notes</label>
            <InputTextArea id="notes" @bind-Value="Model.Notes" class="form-control" rows="3"
                           placeholder="Any special requests or accommodations…" />
            <ValidationMessage For="() => Model.Notes" class="text-danger" />
        </div>

        <button type="submit" class="btn btn-success">Submit Enrollment Request</button>
        <a href="courses" class="btn btn-outline-secondary ms-2">Cancel</a>
    </EditForm>
}

